<?php
 namespace League\CommonMark; use League\CommonMark\Block\Element\AbstractBlock; use League\CommonMark\Block\Renderer\BlockRendererInterface; use League\CommonMark\Inline\Element\AbstractInline; use League\CommonMark\Inline\Renderer\InlineRendererInterface; final class HtmlRenderer implements ElementRendererInterface { protected $environment; public function __construct(EnvironmentInterface $environment) { $this->environment = $environment; } public function getOption(string $option, $default = null) { return $this->environment->getConfig('renderer/' . $option, $default); } public function renderInline(AbstractInline $inline): string { $renderers = $this->environment->getInlineRenderersForClass(\get_class($inline)); foreach ($renderers as $renderer) { if (($result = $renderer->render($inline, $this)) !== null) { return $result; } } throw new \RuntimeException('Unable to find corresponding renderer for inline type ' . \get_class($inline)); } public function renderInlines(iterable $inlines): string { $result = []; foreach ($inlines as $inline) { $result[] = $this->renderInline($inline); } return \implode('', $result); } public function renderBlock(AbstractBlock $block, bool $inTightList = false): string { $renderers = $this->environment->getBlockRenderersForClass(\get_class($block)); foreach ($renderers as $renderer) { if (($result = $renderer->render($block, $this, $inTightList)) !== null) { return $result; } } throw new \RuntimeException('Unable to find corresponding renderer for block type ' . \get_class($block)); } public function renderBlocks(iterable $blocks, bool $inTightList = false): string { $result = []; foreach ($blocks as $block) { $result[] = $this->renderBlock($block, $inTightList); } $separator = $this->getOption('block_separator', "\n"); return \implode($separator, $result); } } 